{
  #pragma omp parallel for collapse(2)
  for (int y = 0; y < Ly; y++) {
    for (int x = 0; x < Lx; x++) {
      int v00 = y * Lx + x;
      int v0p = y * Lx + (x + 1) % Lx;
      int v0m = y * Lx + (Lx + x - 1) % Lx;
