      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(buffer);
  free(h_out);
  free(h_in);
  free(d_in);
  free(d_out);
  return 0;
}

#include <stdlib.h>
